// WatchSwapBridge is a free log subscription operation binding the contract event 0x3094901d3684b9dca13f7221aa2b7084ae31eb4d05822317d8ad507ec613726c.
//
// Solidity: event SwapBridge(address indexed user, address indexed tokenIn, address indexed tokenOut, uint256 amountIn, uint256 amountOut, uint256 toChainID, uint256 initiateIndex, uint256 bridgeValue, uint256 networkFee, uint256 exFee)
func (_SwapBridgeRouter *SwapBridgeRouterFilterer) WatchSwapBridge(opts *bind.WatchOpts, sink chan<- *SwapBridgeRouterSwapBridge, user []common.Address, tokenIn []common.Address, tokenOut []common.Address) (event.Subscription, error) {

	var userRule []interface{}
	for _, userItem := range user {
		userRule = append(userRule, userItem)
	}
	var tokenInRule []interface{}
	for _, tokenInItem := range tokenIn {
		tokenInRule = append(tokenInRule, tokenInItem)
	}
	var tokenOutRule []interface{}
	for _, tokenOutItem := range tokenOut {
		tokenOutRule = append(tokenOutRule, tokenOutItem)
	}

	logs, sub, err := _SwapBridgeRouter.contract.WatchLogs(opts, "SwapBridge", userRule, tokenInRule, tokenOutRule)
	if err != nil {
		return nil, err
	}
	return event.NewSubscription(func(quit <-chan struct{}) error {
		defer sub.Unsubscribe()
		for {
			select {
			case log := <-logs:
				// New log arrived, parse the event and forward to the user
				event := new(SwapBridgeRouterSwapBridge)
				if err := _SwapBridgeRouter.contract.UnpackLog(event, "SwapBridge", log); err != nil {
					return err
				}
				event.Raw = log

				select {
				case sink <- event:
				case err := <-sub.Err():
					return err
				case <-quit:
					return nil
				}
			case err := <-sub.Err():
				return err
			case <-quit:
				return nil
			}
		}
	}), nil
}

